function e(e){let t=Math.max(0,e.totalTasks),n=Math.max(0,Math.min(e.completedTasks,t)),r=Math.max(t-n,0);return{totalTasks:t,completedTasks:n,remainingTasks:r,completionRate:t===0?0:Math.round(n/t*100),firstIncompleteTaskTitle:r>0?e.firstIncompleteTaskTitle:null,masbahaTodayCount:Math.max(0,e.masbahaTodayCount),masbahaTarget:Math.max(0,e.masbahaTarget),azkarTodayCount:Math.max(0,e.azkarTodayCount),duasTodayCount:Math.max(0,e.duasTodayCount),namesTodayCount:Math.max(0,e.namesTodayCount),quranTodayReadings:Math.max(0,e.quranTodayReadings),quranBookmark:e.quranBookmark,isFullyCompleted:t>0&&n>=t}}export{e as t};